/**
 * Show comment input form
 */
function showCommentInput(lineEl, filePath, lineNum, onClose) {
  // Remove any existing input
  const existing = document.querySelector('.comment-input-form');
  if (existing) {
    existing.closest('.comment-row')?.remove();
  }

  // Create input form
  const form = document.createElement('div');
  form.className = 'comment-input-form';
  form.innerHTML = `
    <div class="comment-input-header">
      <span>Comment on line ${lineNum}</span>
      <button class="close-btn" title="Cancel">&times;</button>
    </div>
    <textarea placeholder="Add your comment..." rows="3"></textarea>
    <div class="comment-input-actions">
      <button class="cancel-btn">Cancel</button>
      <button class="submit-btn">Add Comment</button>
    </div>
  `;

  // Find the row to insert after
  const row = lineEl.closest('tr') || lineEl.closest('.d2h-code-line-ctn');
  if (row && row.parentNode) {
    const wrapper = document.createElement('tr');
    wrapper.className = 'comment-row';
    const td = document.createElement('td');
    td.colSpan = 4;
    td.appendChild(form);
    wrapper.appendChild(td);
    row.parentNode.insertBefore(wrapper, row.nextSibling);
  }

  // Focus textarea
  const textarea = form.querySelector('textarea');
  setTimeout(() => textarea.focus(), 0);

  const closeForm = () => {
    form.closest('.comment-row')?.remove();
    if (onClose) onClose();
  };

  // Handle cancel
  form.querySelector('.close-btn').addEventListener('click', closeForm);
  form.querySelector('.cancel-btn').addEventListener('click', closeForm);

  // Handle submit
  form.querySelector('.submit-btn').addEventListener('click', () => {
    const text = textarea.value.trim();
    if (text) {
      vscode.postMessage({
        type: 'addComment',
        filePath,
        line: lineNum,
        text
      });
      closeForm();
    }
  });

  // Handle Cmd/Ctrl+Enter to submit, Escape to cancel
  textarea.addEventListener('keydown', (e) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
      form.querySelector('.submit-btn').click();
    }
    if (e.key === 'Escape') {
      closeForm();
    }
  });
}

